let raw = $.steps.fetchData.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return { data: JSON.parse(raw), parseSuccess: true }; } catch(e) { return { data: [], parseSuccess: false, error: e.message, raw: raw.slice(0, 500) }; }

const data = $.steps.parseRawJson.output.data;
if (!Array.isArray(data)) {
  const keys = Object.keys(data);
  const summary = { type: 'object', keyCount: keys.length, keys: keys.slice(0, 20), sampleValues: {} };
  keys.slice(0, 10).forEach(k => {
    const val = data[k];
    summary.sampleValues[k] = { type: typeof val, value: JSON.stringify(val).slice(0, 100) };
  });
  return { isArray: false, summary, itemCount: 1, transformed: [data] };
}
const items = data.slice(0, 20);
const fieldTypes = {};
if (items.length > 0) {
  Object.keys(items[0]).forEach(k => {
    const values = items.map(i => i[k]).filter(v => v != null);
    const types = [...new Set(values.map(v => typeof v))];
    fieldTypes[k] = { types: types.join('/'), sampleValues: values.slice(0, 3).map(v => String(v).slice(0, 50)) };
  });
}
const stats = {};
Object.keys(items[0] || {}).forEach(k => {
  const nums = items.map(i => Number(i[k])).filter(n => !isNaN(n));
  if (nums.length > items.length * 0.5) {
    stats[k] = { min: Math.min(...nums), max: Math.max(...nums), avg: Math.round(nums.reduce((a, b) => a + b, 0) / nums.length * 100) / 100 };
  }
});
const enriched = items.map((item, i) => ({ _index: i + 1, _keyCount: Object.keys(item).length, ...item }));
return { isArray: true, itemCount: data.length, shownCount: items.length, fieldTypes, stats, transformed: enriched };

const t = $.steps.transformData.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Data Transformer Results' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* `' + $.input.apiUrl + '`\n*Parse success:* ' + ($.steps.parseRawJson.output.parseSuccess ? ':white_check_mark:' : ':x:') } });
blocks.push({ type: 'divider' });
if (t.isArray) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Data Overview*\nTotal items: *' + t.itemCount + '* | Shown: *' + t.shownCount + '*' } });
  if (t.fieldTypes) {
    let schemaText = '*Field Schema*\n';
    Object.entries(t.fieldTypes).forEach(([k, v]) => {
      schemaText += '`' + k + '` _(' + v.types + ')_ — e.g. ' + v.sampleValues.slice(0, 2).join(', ') + '\n';
    });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: schemaText.slice(0, 1900) } });
  }
  if (t.stats && Object.keys(t.stats).length > 0) {
    const fields = Object.entries(t.stats).slice(0, 10).map(([k, v]) => ({
      type: 'mrkdwn', text: '*' + k + '*\nMin: ' + v.min + ' | Max: ' + v.max + ' | Avg: ' + v.avg
    }));
    for (let i = 0; i < fields.length; i += 2) {
      blocks.push({ type: 'section', fields: fields.slice(i, i + 2) });
    }
  }
  blocks.push({ type: 'divider' });
  let sampleText = '*Sample Records*\n';
  t.transformed.slice(0, 3).forEach(item => {
    sampleText += '```' + JSON.stringify(item, null, 2).slice(0, 500) + '```\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sampleText.slice(0, 1900) } });
} else {
  const s = t.summary;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Data Type:* Object\n*Keys:* ' + s.keyCount + '\n*Fields:* ' + s.keys.join(', ') } });
  if (s.sampleValues) {
    const fields = Object.entries(s.sampleValues).slice(0, 10).map(([k, v]) => ({
      type: 'mrkdwn', text: '*' + k + '* _(' + v.type + ')_\n' + v.value
    }));
    for (let i = 0; i < fields.length; i += 2) {
      blocks.push({ type: 'section', fields: fields.slice(i, i + 2) });
    }
  }
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Fetched and transformed by One CLI Data Transformer' }] });
return { blocks, fallback: 'Data Transformer: ' + t.itemCount + ' items from ' + $.input.apiUrl };
